import{_ as i,o as a,c as t,a2 as n}from"./chunks/framework.OWFDNrRT.js";const h=JSON.parse('{"title":"ADR-010: Deterministic Star-Wars-Style Asset Intake Pipeline","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-010-asset-intake-pipeline.md","filePath":"adr/ADR-010-asset-intake-pipeline.md","lastUpdated":1773460793000}'),o={name:"adr/ADR-010-asset-intake-pipeline.md"};function s(r,e,l,c,d,u){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="adr-010-deterministic-star-wars-style-asset-intake-pipeline" tabindex="-1">ADR-010: Deterministic Star-Wars-Style Asset Intake Pipeline <a class="header-anchor" href="#adr-010-deterministic-star-wars-style-asset-intake-pipeline" aria-label="Permalink to &quot;ADR-010: Deterministic Star-Wars-Style Asset Intake Pipeline&quot;">​</a></h1><p><strong>Status</strong>: Proposed <strong>Date</strong>: 2026-03-11 <strong>Deciders</strong>: Agent Org</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The current mod workflow can ingest assets through ad-hoc manual steps, but a repeatable low-poly conversion for a Star Wars conversion requires:</p><ul><li>deterministic source discovery (prefer API-driven),</li><li>provenance-first manifests,</li><li>explicit legal/IP state separate from technical quality,</li><li>machine-readable scoring and rejection rules,</li><li>and non-destructive registration before runtime use.</li></ul><p>The immediate need is a pre-implementation contract for an <code>assetctl</code> toolchain, not a full production asset conversion subsystem.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><ul><li>Add an explicit agent-facing intake pipeline with machine-readable schemas and policy files.</li><li>Add <code>assetctl</code> as a dedicated CLI surface for <code>search</code>, <code>intake</code>, <code>normalize</code>, <code>validate</code>, <code>stylize</code>, <code>register</code>, <code>export-unity</code>.</li><li>Use a source-tier model (Sketchfab primary, BlendSwap secondary, ModDB reference, browser fallback last).</li><li>Track two independent state dimensions on each asset: <ul><li><code>technical_status</code> (discovered → normalized → validated → ready_for_prototype),</li><li><code>ip_status</code> (generic_safe vs high_risk_do_not_ship).</li></ul></li><li>Require a manifest conforming to <code>schemas/asset-manifest.schema.json</code> before promotion beyond prototype.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>Legal/provenance decisions become auditable and machine-enforced instead of informal.</li><li>Asset quality variance is controlled through explicit technical gates and validation reports.</li><li>Source/API strategy is configurable without code changes via policy documents.</li><li>Pre-implementation artifacts remain non-invasive: no runtime coupling before design freeze.</li><li>Future release-safe workflows can be added by changing policy and status transitions, not by rewriting the whole pipeline.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><ul><li>One-off manual asset import: <ul><li>rejected due to non-repeatability and weak provenance control.</li></ul></li><li>Full external DAM integration: <ul><li>rejected in V1 due to complexity and scope, but preserved as a future extension.</li></ul></li><li>Browser automation as default: <ul><li>rejected because it is brittle and harder to audit for policy and retries.</li></ul></li></ul>',12)])])}const m=i(o,[["render",s]]);export{h as __pageData,m as default};
